const t={macroDesigner:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Симулируйте G-code офлайн — вставьте или напишите программу и посмотрите траекторию печатающей головки, ограничивающую рамку, суммарные перемещения и экструзию, а также оценку времени, не трогая принтер. Изучайте встроенную библиотеку макросов для справки."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Справка"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"О Macro Designer"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Закрыть"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Как пользоваться"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Введите или вставьте G-code в редактор (для начала загружен пример квадрата)."}},{t:0,b:{t:2,i:[{t:3}],s:"Нажмите «Симулировать» — обновятся 2D-траектория и статистика."}},{t:0,b:{t:2,i:[{t:3}],s:"Сплошные линии — это перемещения с экструзией; бледные пунктирные линии — холостые перемещения."}},{t:0,b:{t:2,i:[{t:3}],s:"Изучите библиотеку макросов и вставьте один, чтобы начать с его команд."}}],topics:{simulator:{title:{t:0,b:{t:2,i:[{t:3}],s:"Симулятор"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Он выполняет программу на виртуальной печатающей головке: перемещения G0/G1, G90/G91 (абсолютные/относительные координаты), M82/M83 (режим экструдера), G92 (установка позиции) и G28 (парковка → начало координат). Он сообщает траекторию, ограничивающую рамку, суммарные холостые перемещения и экструзию, приблизительную оценку времени по скоростям подачи и хронологию по командам. На принтер ничего не отправляется."}}},motion:{title:{t:0,b:{t:2,i:[{t:3}],s:"Траектория и время"}},body:{t:0,b:{t:2,i:[{t:3}],s:"2D-вид показывает траекторию в плоскости XY (Z учитывается в границах). Оценка времени делит длину каждого перемещения на его скорость подачи — она не учитывает ускорение, поэтому это приблизительная нижняя граница, а не точное время печати. Команды, которые симулятор не моделирует (например, M-codes, высокоуровневые макросы), перечисляются как предупреждения и пропускаются."}}},macros:{title:{t:0,b:{t:2,i:[{t:3}],s:"Библиотека макросов"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Справочный набор распространённых макросов Klipper с их именем, назначением и необходимыми им секциями конфигурации. «Вставить» помещает высокоуровневые команды макроса в редактор как отправную точку — учтите, что на принтере они разворачиваются дальше (полное разворачивание Jinja/макросов скоро появится)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Глоссарий"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{gcode:{term:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Построчный язык движения, который выполняет принтер (перемещения, температуры, вентилятор, …)."}}},feedrate:{term:{t:0,b:{t:2,i:[{t:3}],s:"Скорость подачи (F)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Скорость перемещения в mm/min — F1200 это 20 mm/s. Задаёт, насколько быстро выполняется каждое перемещение."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"Макрос"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Именованная многоразовая команда (например, QUAD_GANTRY_LEVEL), которая разворачивается в последовательность G-code."}}}}},editor:{label:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},simulate:{t:0,b:{t:2,i:[{t:3}],s:"Симулировать"}},simulating:{t:0,b:{t:2,i:[{t:3}],s:"Симуляция…"}},sample:{t:0,b:{t:2,i:[{t:3}],s:"Загрузить пример"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Очистить"}}},library:{label:{t:0,b:{t:2,i:[{t:3}],s:"Встроенные макросы"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Поиск по макросам…"}},insert:{t:0,b:{t:2,i:[{t:3}],s:"Вставить в редактор"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Требуется: "},{t:4,k:"sections"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Симуляция"}},moves:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" перемещений"}]}},distance:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm холостого хода"}]}},extrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm экструзии"}]}},time:{t:0,b:{t:2,i:[{t:3,v:"~"},{t:4,k:"s"},{t:3,v:" с"}]}},bounds:{t:0,b:{t:2,i:[{t:3}],s:"Границы"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Нет перемещений для симуляции."}}},path:{title:{t:0,b:{t:2,i:[{t:3}],s:"Траектория головки (XY)"}},noPath:{t:0,b:{t:2,i:[{t:3}],s:"Запустите симуляцию, чтобы увидеть траекторию."}}},timeline:{title:{t:0,b:{t:2,i:[{t:3}],s:"Хронология"}},line:{t:0,b:{t:2,i:[{t:3}],s:"Строка"}},cmd:{t:0,b:{t:2,i:[{t:3}],s:"Команда"}},action:{t:0,b:{t:2,i:[{t:3}],s:"Действие"}}},warnings:{title:{t:0,b:{t:2,i:[{t:3}],s:"Предупреждения"}}},explain:{title:{t:0,b:{t:2,i:[{t:3}],s:"Объяснить этот макрос"}},travel:{t:0,b:{t:2,i:[{t:3,v:"Быстрый переход в X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" со скоростью "},{t:4,k:"f"},{t:3,v:" мм/мин"}]}},print:{t:0,b:{t:2,i:[{t:3,v:"Печатное движение — выдавить "},{t:4,k:"e"},{t:3,v:" мм на "},{t:4,k:"d"},{t:3,v:" мм до X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" со скоростью "},{t:4,k:"f"},{t:3,v:" мм/мин"}]}},retract:{t:0,b:{t:2,i:[{t:3,v:"Ретракт "},{t:4,k:"e"},{t:3,v:" мм"}]}},prime:{t:0,b:{t:2,i:[{t:3,v:"Выдавить "},{t:4,k:"e"},{t:3,v:" мм на месте"}]}},noMove:{t:0,b:{t:2,i:[{t:3}],s:"Без движения"}},absXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Переключить на абсолютное позиционирование (G90)"}},relXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Переключить на относительное позиционирование (G91)"}},absE:{t:0,b:{t:2,i:[{t:3}],s:"Переключить на абсолютную экструзию (M82)"}},relE:{t:0,b:{t:2,i:[{t:3}],s:"Переключить на относительную экструзию (M83)"}},setPos:{t:0,b:{t:2,i:[{t:3}],s:"Задать текущую позицию (G92)"}},home:{t:0,b:{t:2,i:[{t:3}],s:"Парковка осей (G28) → начало"}},abs:{t:0,b:{t:2,i:[{t:3}],s:"АБС"}},rel:{t:0,b:{t:2,i:[{t:3}],s:"ОТН"}},cum:{t:0,b:{t:2,i:[{t:3,v:"пока: "},{t:4,k:"d"},{t:3,v:" мм · "},{t:4,k:"e"},{t:3,v:" мм · ~"},{t:4,k:"s"},{t:3,v:" с"}]}},note:{t:0,b:{t:2,i:[{t:3}],s:"Строки с неразрешёнными выражениями или управлением Jinja не моделируются и здесь опущены."}}},live:{label:{t:0,b:{t:2,i:[{t:3}],s:"С принтера"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Выберите один из установленных макросов…"}},hint:{t:0,b:{t:2,i:[{t:3,v:"На принтере найдено "},{t:4,k:"n"},{t:3,v:" макросов — выберите один, чтобы загрузить его G-code и смоделировать."}]}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Принтер недоступен — подключитесь, чтобы загрузить установленные макросы."}},params:{t:0,b:{t:2,i:[{t:3}],s:"Параметры макроса"}}}}};export{t as default};
